import React, { useState, useEffect } from "react";

const FetchedMatrix = ({ grid, rows, columns }) => {
  const [userGrid, setUserGrid] = useState([]);

  useEffect(() => {
    // Initialize the user grid to all 0s
    let newGrid = [];
    for (let i = 0; i < rows; i++) {
      let row = [];
      for (let j = 0; j < columns; j++) {
        row.push(0);
      }
      newGrid.push(row);
    }
    setUserGrid(newGrid);
  }, [rows, columns]);

  // Function to handle box click
  const handleBoxClick = (row, col) => {
    // Copy current user grid state
    let newUserGrid = [...userGrid];
    // Toggle the box value between 0 and 1
    newUserGrid[row][col] = newUserGrid[row][col] === 0 ? 1 : 0;
    // Update user grid state
    setUserGrid(newUserGrid);
  };

  // Render matrix
  const renderMatrix = () => {
    let matrix = [];
    for (let i = 0; i < rows; i++) {
      let row = [];
      for (let j = 0; j < columns; j++) {
        if (grid[i] && grid[i][j] !== undefined) {
          row.push(
            <div
              className="grid-square"
              style={{ backgroundColor: userGrid[i][j] === 0 ? "white" : "black" }}
              onClick={() => handleBoxClick(i, j)}
              key={`${i}-${j}`}
            />
          );
        }
      }
      matrix.push(<div className="grid-row" style={{ display: 'flex', flexDirection: 'column' }} key={i}>{row}</div>);
    }
    return matrix;
  };

  // Check if the user grid and the fetched grid match
  const match = JSON.stringify(grid) === JSON.stringify(userGrid);

  return (
    <div className="nonogram-container">
        <h1>Nonogram Puzzle Game</h1>
      <div className="grid-container">{renderMatrix()}</div>
      {match && <div>WIN!</div>}
    </div>
  );
};

export default FetchedMatrix;
